class Solution:
    def canPartitionKSubsets(self, nums: List[int], k: int) -> bool:
        total = sum(nums)
        if total % k:
            return False
        target = total // k
        nums.sort(reverse=True)
        n = len(nums)
        if nums[0] > target:
            return False

        used = [False] * n

        def backtrack(i, k_left, cur_sum):
            if k_left == 0:
                return True
            if cur_sum == target:
                return backtrack(0, k_left - 1, 0)
            for j in range(i, n):
                if not used[j] and cur_sum + nums[j] <= target:
                    if j > 0 and nums[j] == nums[j-1] and not used[j-1]:
                        continue
                    used[j] = True
                    if backtrack(j + 1, k_left, cur_sum + nums[j]):
                        return True
                    used[j] = False
                    if cur_sum == 0:
                        break
            return False

        return backtrack(0, k, 0)
```
efficiency: HIGH
time complexity: O(k * 2^n)
space complexity: O(n)
energy implications: MEDIUM
explanation: Uses backtracking with pruning: sorts descending to fail early, skips duplicate values, and stops when a zero-sum bucket fails. The bitmask state space is 2^16 = 65536 at worst, which is acceptable for n ≤ 16.

